import { createClient, type SupabaseClient } from '@supabase/supabase-js'

const supabaseUrl = import.meta.env.VITE_SUPABASE_URL as string | undefined
const supabaseAnonKey = import.meta.env.VITE_SUPABASE_ANON_KEY as string | undefined

export const supabaseEnabled = Boolean(supabaseUrl && supabaseAnonKey)

if (!supabaseEnabled) {
  console.warn(
    'Missing VITE_SUPABASE_URL or VITE_SUPABASE_ANON_KEY — auth is disabled.',
  )
}

// No-op stub so consumers never need null checks.
const noopAuth = {
  getSession: async () => ({ data: { session: null }, error: null }),
  onAuthStateChange: () => ({ data: { subscription: { unsubscribe: () => {} } } }),
  signInWithOAuth: async () => ({ data: { provider: '', url: '' }, error: null }),
  signOut: async () => ({ error: null }),
}

export const supabase: SupabaseClient = supabaseEnabled
  ? createClient(supabaseUrl!, supabaseAnonKey!)
  : ({ auth: noopAuth } as unknown as SupabaseClient)

import * as matchers from '@testing-library/jest-dom/matchers'
import { expect, afterEach } from 'vitest'
import { cleanup } from '@testing-library/react'

expect.extend(matchers)

// Cleanup DOM after each test (required when not using vitest globals)
afterEach(() => {
  cleanup()
})

import { describe, it, expect, vi, beforeEach, afterEach } from 'vitest'

const mockCreateClient = vi.fn().mockReturnValue({ auth: {} })

vi.mock('@supabase/supabase-js', () => ({
  createClient: mockCreateClient,
}))

describe('supabase client', () => {
  beforeEach(() => {
    vi.resetModules()
    mockCreateClient.mockClear()
  })

  afterEach(() => {
    vi.unstubAllEnvs()
  })

  it('provides a no-op stub when env vars are missing', async () => {
    vi.stubEnv('VITE_SUPABASE_URL', '')
    vi.stubEnv('VITE_SUPABASE_ANON_KEY', '')
    const { supabase, supabaseEnabled } = await import('./supabase')
    expect(supabaseEnabled).toBe(false)
    expect(mockCreateClient).not.toHaveBeenCalled()
    // Stub still exposes auth methods so consumers don't need null checks
    expect(supabase.auth).toBeDefined()
    const { data } = await supabase.auth.getSession()
    expect(data.session).toBeNull()
  })

  it('calls createClient when env vars are set', async () => {
    vi.stubEnv('VITE_SUPABASE_URL', 'https://test.supabase.co')
    vi.stubEnv('VITE_SUPABASE_ANON_KEY', 'test-anon-key')
    const { supabase, supabaseEnabled } = await import('./supabase')
    expect(supabaseEnabled).toBe(true)
    expect(supabase).toBeDefined()
    expect(supabase).toHaveProperty('auth')
    expect(mockCreateClient).toHaveBeenCalledWith(
      'https://test.supabase.co',
      'test-anon-key',
    )
  })
})

import { defineConfig } from 'vitest/config'
